-- ── Validação pós-migração ──
SELECT COUNT(*) AS esforcos FROM esforcos_amostragem ea
  JOIN pontos_coleta pc ON ea.id_ponto_coleta=pc.id_ponto_coleta
  WHERE pc.id_projeto=165 AND ea.grupo_biologico='Herpetofauna';

SELECT COUNT(*) AS resultados FROM resultados_herpetofauna rh
  JOIN esforcos_amostragem ea ON rh.id_esforco=ea.id_esforco
  JOIN pontos_coleta pc ON ea.id_ponto_coleta=pc.id_ponto_coleta
  WHERE pc.id_projeto=165;